mapper.select:
SELECT -- 질문(헤더) 컬럼 q.qna_oid, q.user_id, q.wrt_nm, q.pswd, q.qna_ttl, q.qna_cn, q.ctgry, cd.cd_nm AS ctgry_nm, q.ans_yn, q.prvt_pst_yn, q.use_yn, q.inq_cnt, q.reg_dt, q.mdfcn_dt,
-- 답변(아이템) 컬럼 a.qna_oid AS item_qna_oid, a.up_qna_oid, a.user_id AS item_user_id, a.wrt_nm AS item_writer_nm, a.qna_cn AS item_content, a.reg_dt AS item_reg_dt, a.mdfcn_dt AS item_upd_dt FROM ${schema}.qna q LEFT JOIN ${schema}.qna a ON q.qna_oid = a.up_qna_oid LEFT JOIN ${schema}.grp_cd gc ON gc.grp_cd = 'CATEGORY_TYPE' AND gc.use_yn = 'Y' LEFT JOIN ${schema}.cd cd ON cd.grp_cd_oid = gc.grp_cd_oid AND cd.use_yn = 'Y' AND cd.cd_val = q.ctgry
q.up_qna_oid IS NULL
AND ( q.qna_oid LIKE CONCAT('%', #{keyword}, '%') OR q.qna_ttl LIKE CONCAT('%', #{keyword}, '%') )
AND DATE_FORMAT(q.reg_dt, '%Y-%m-%d') >= #{regDtSt} AND DATE_FORMAT(q.reg_dt, '%Y-%m-%d') <= #{regDtEd}
AND q.ans_yn = #{ansYn}
AND q.ctgry = #{ctgry}
ORDER BY q.reg_dt DESC, a.reg_dt

SELECT q.qna_oid AS qnaOid, CASE WHEN c.cd_nm IS NULL THEN '기타' WHEN c.cd_nm = '기타' THEN c.cd_nm ELSE CONCAT(c.cd_nm) END AS ctgry, q.qna_ttl AS qnaTtl, q.reg_dt AS regDt, (SELECT reg_dt FROM ${schema}.qna WHERE up_qna_oid = q.qna_oid AND use_yn = 'Y' ORDER BY reg_dt ASC LIMIT 1) AS answerRegDt, q.ans_yn AS ansYn, (SELECT wrt_nm FROM ${schema}.qna WHERE up_qna_oid = q.qna_oid AND use_yn = 'Y' ORDER BY reg_dt ASC LIMIT 1) AS answerWriterNm, q.prvt_pst_yn AS secretYn, CASE WHEN q.prvt_pst_yn = 'Y' THEN '비공개' WHEN q.prvt_pst_yn = 'N' THEN '공개' ELSE '' END AS secretYnStr, q.inq_cnt AS inqCnt FROM ${schema}.qna q LEFT JOIN ${schema}.cd c ON c.grp_cd_oid = 84 AND c.cd_val = q.ctgry AND c.use_yn = 'Y'
q.up_qna_oid IS NULL AND q.use_yn = 'Y'
AND ( q.qna_oid LIKE CONCAT('%', #{keyword}, '%') OR q.qna_ttl LIKE CONCAT('%', #{keyword}, '%') )
AND q.ans_yn = #{ansYn}
AND q.reg_dt >= #{regDtSt}
AND q.reg_dt < DATE_ADD(#{regDtEd}, INTERVAL 1 DAY)
AND q.ctgry = #{ctgry}
ORDER BY q.reg_dt DESC

mapper.insert:
INSERT INTO ${schema}.qna (
	up_qna_oid
	, user_id
	, wrt_nm
	, qna_ttl
	, qna_cn
	, ctgry
	, ans_yn
	, reg_dt
	, mdfcn_dt
) VALUES (
	#{upQnaOid}
	, #{userId}
	, #{wrtNm}
	, #{qnaTtl}
	, #{qnaCn}
	, #{ctgry}
	, #{ansYn}
	, NOW()
	, NOW()
)

INSERT INTO ${schema}.qna_dgstfn_evl (
	  tbl_nm
	, tbl_oid
	, stts
	, reg_id
	, reg_dt
) VALUES (
	  #{tblNm}
	, #{tblOid}
	, 'PENDING'
	, #{regId}
	, NOW()
)

mapper.update:
	UPDATE ${schema}.qna
	SET
		use_yn = 'N'
		, mdfcn_dt = NOW()
	WHERE qna_oid = #{qnaOid}
    OR up_qna_oid = #{qnaOid}

UPDATE ${schema}.qna
SET inq_cnt = inq_cnt + 1
WHERE qna_oid = #{qnaOid}
